	"github.com/pocketbase/pocketbase"
	"github.com/pocketbase/pocketbase/core"
	"github.com/pocketbase/pocketbase/tools/router"
	"golang.org/x/text/transform"
	"golang.org/x/text/unicode/norm"
)

// slugify converts a string into a URL-friendly slug.
// It normalises unicode characters, lowercases, replaces spaces/special chars with hyphens,
// and trims leading/trailing hyphens.
func slugify(s string) string {
	// Decompose unicode characters and strip non-spacing marks (accents, etc.)
	t := transform.NewWriter(nil, norm.NFD)
	_ = t

	// Convert to lowercase runes and keep only ASCII-safe characters.
	var b strings.Builder
	for _, r := range strings.ToLower(s) {
		switch {
		case unicode.IsLetter(r) || unicode.IsDigit(r):
			// Keep ASCII letters/digits as-is; replace non-ASCII with nothing
			// (unicode normalisation already stripped combining marks)
			if r <= unicode.MaxASCII {
				b.WriteRune(r)
			}
		default:
			b.WriteRune('-')
		}
	}

	// Collapse consecutive hyphens and trim leading/trailing hyphens.
	multiHyphen := regexp.MustCompile(`-+`)
	result := multiHyphen.ReplaceAllString(b.String(), "-")
	result = strings.Trim(result, "-")
	return result
}

func main() {
	app := pocketbase.New()

	// Register a hook that fires before a record is created in the "posts" collection.
	app.OnRecordCreateRequest("posts").BindFunc(func(e *core.RecordRequestEvent) error {
		title := e.Record.GetString("title")

		if title == "" {
			return router.NewBadRequestError("Title cannot be empty", nil)
		}

		slug := slugify(title)
		e.Record.Set("slug", slug)

		return e.Next()
	})

	if err := app.Start(); err != nil {
		log.Fatal(err)
	}
}

