package main

import (
	"bytes"
	"log"
	"regexp"
	"strings"

	"github.com/pocketbase/pocketbase"
	"github.com/pocketbase/pocketbase/core"
	"github.com/pocketbase/pocketbase/tools/router"
	"golang.org/x/text/transform"
	"golang.org/x/text/unicode/norm"
)

var (
	// nonAlphanumericRegex matches any character that is not a letter, digit, or hyphen.
	nonAlphanumericRegex = regexp.MustCompile(`[^a-z0-9]+`)
	// multiHyphenRegex collapses consecutive hyphens into one.
	multiHyphenRegex = regexp.MustCompile(`-{2,}`)
)

// slugify converts an arbitrary string into a URL-friendly slug.
// Steps:
//  1. Unicode NFD decomposition + strip non-spacing marks (strips accents).
//  2. Lowercase.
//  3. Replace non-alphanumeric characters with a hyphen.
//  4. Collapse consecutive hyphens.
//  5. Trim leading/trailing hyphens.
func slugify(s string) string {
	// Step 1 – normalise unicode: decompose and remove combining marks.
	t := transform.Chain(norm.NFD, transform.RemoveFunc(func(r rune) bool {
		// Remove non-spacing marks (category Mn) that represent accent/diacritics.
		return norm.NFC.QuickSpan([]byte(string(r))) == 0
	}))
	cleaned, _, _ := transform.String(t, s)

	// Step 2 – lowercase.
	cleaned = strings.ToLower(cleaned)

	// Step 3 – replace non-alphanumeric characters (including spaces) with hyphens.
	cleaned = nonAlphanumericRegex.ReplaceAllString(cleaned, "-")

	// Step 4 – collapse consecutive hyphens.
	cleaned = multiHyphenRegex.ReplaceAllString(cleaned, "-")

	// Step 5 – trim leading/trailing hyphens.
	cleaned = strings.Trim(cleaned, "-")

	return cleaned
}

// isMn reports whether a rune is a non-spacing mark (used to strip accents).
// We need a bytes.Buffer reference to silence the unused import; kept for clarity.
var _ = bytes.NewBuffer

func main() {
	app := pocketbase.New()

	// Register a hook that fires before a record is created in the "posts" collection.
	// The hook validates the title, generates a URL slug, and stores it on the record.
	app.OnRecordCreateRequest("posts").BindFunc(func(e *core.RecordRequestEvent) error {
		title := e.Record.GetString("title")

		if title == "" {
			return router.NewBadRequestError("Title cannot be empty", nil)
		}

		slug := slugify(title)
		e.Record.Set("slug", slug)

		// Propagate the hook chain so the record is actually saved.
		return e.Next()
	})

	if err := app.Start(); err != nil {
		log.Fatal(err)
	}
}

package main

import (
	"log"
	"regexp"
	"strings"
	"unicode"

	"github.com/pocketbase/pocketbase"
	"github.com/pocketbase/pocketbase/core"
	"github.com/pocketbase/pocketbase/tools/router"
	"golang.org/x/text/transform"
	"golang.org/x/text/unicode/norm"
)

var (
	// nonAlphanumericRegex matches any character that is not an ASCII letter or digit.
	nonAlphanumericRegex = regexp.MustCompile(`[^a-z0-9]+`)
	// multiHyphenRegex collapses consecutive hyphens into one.
	multiHyphenRegex = regexp.MustCompile(`-{2,}`)
)

// slugify converts an arbitrary string into a URL-friendly slug.
// Steps:
//  1. Unicode NFD decomposition + strip non-spacing marks (strips accents / diacritics).
//  2. Lowercase.
//  3. Replace non-alphanumeric characters (spaces, punctuation, …) with a hyphen.
//  4. Collapse consecutive hyphens into a single one.
//  5. Trim leading/trailing hyphens.
func slugify(s string) string {
	// Decompose unicode characters and remove non-spacing combining marks (accents).
	t := transform.Chain(norm.NFD, transform.RemoveFunc(func(r rune) bool {
		return unicode.Is(unicode.Mn, r) // Mn = non-spacing mark
	}))
	normalised, _, _ := transform.String(t, s)

	// Lowercase, replace non-alphanumeric chars, collapse/trim hyphens.
	result := strings.ToLower(normalised)
	result = nonAlphanumericRegex.ReplaceAllString(result, "-")
	result = multiHyphenRegex.ReplaceAllString(result, "-")
	result = strings.Trim(result, "-")

	return result
}

func main() {
	app := pocketbase.New()

	// Register a hook that fires before a record is created in the "posts" collection.
	// Validates the title, derives a URL slug, and sets it on the record before save.
	app.OnRecordCreateRequest("posts").BindFunc(func(e *core.RecordRequestEvent) error {
		title := e.Record.GetString("title")

		if title == "" {
			return router.NewBadRequestError("Title cannot be empty", nil)
		}

		e.Record.Set("slug", slugify(title))

		// Continue the hook chain so the record is actually persisted.
		return e.Next()
	})

	if err := app.Start(); err != nil {
		log.Fatal(err)
	}
}
